export default function AdminLayout({ children }) {
  const pathname = usePathname();
  const hideHeader = pathname !== "/dashboard/admin";

  return (
    <WorkspaceLayout
      icon={ADMIN_ICON}
      module="Administration"
      moduleHref="/dashboard/admin"
      title="Administration"
      description="Manage users, roles, system settings, and operational configurations."
      hideHeader={hideHeader}
      hideTitleBlock={true}
    >
      {children}
    </WorkspaceLayout>
  );
}
